module design_30(
    input clk,
    input rst_n,
    output [3:0] data_out
);
    // 设计实现: 中断信号输出
    reg [3:0] counter;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            counter <= 0;
        else
            counter <= counter + 1;
    end

    assign data_out = counter;
endmodule

